import{_ as t,o,c as s,a2 as n}from"./chunks/framework.DvFsUg-r.js";const d=JSON.parse('{"title":"메뉴 구조 최적화 (상단 그룹화 · 좌측 레벨 정리)","description":"","frontmatter":{"title":"메뉴 구조 최적화 (상단 그룹화 · 좌측 레벨 정리)","feature_id":"009","status":"done","created":"2026-06-03 05:43 (KST)","date":"2026-06-03T00:00:00.000Z","tags":["vitepress","navigation","information-architecture","ux"]},"headers":[],"relativePath":"specs/009-nav-menu-restructure/spec.md","filePath":"specs/009-nav-menu-restructure/spec.md","lastUpdated":null}'),i={name:"specs/009-nav-menu-restructure/spec.md"};function e(a,r,l,g,u,c){return o(),s("div",null,[...r[0]||(r[0]=[n('<h1 id="spec-메뉴-구조-최적화-상단-그룹화-·-좌측-레벨-정리" tabindex="-1">Spec: 메뉴 구조 최적화 (상단 그룹화 · 좌측 레벨 정리) <a class="header-anchor" href="#spec-메뉴-구조-최적화-상단-그룹화-·-좌측-레벨-정리" aria-label="Permalink to &quot;Spec: 메뉴 구조 최적화 (상단 그룹화 · 좌측 레벨 정리)&quot;">​</a></h1><h2 id="why-문제-목적" tabindex="-1">Why (문제 / 목적) <a class="header-anchor" href="#why-문제-목적" aria-label="Permalink to &quot;Why (문제 / 목적)&quot;">​</a></h2><p>블로그 사이트(<code>blog/</code>)의 콘텐츠가 빠르게 늘면서 <strong>탐색 구조(IA)</strong> 가 한계에 부딪혔다.</p><ul><li><strong>상단 메뉴가 평평하게 9개</strong>(홈·개요·저널·명세·스킬 강연·Cowork 가이드· Hermes 보고서·Blog Archive·GitHub)로 나열되어 있다. 서로 성격이 다른 항목이 같은 층위에 섞여 있어, 처음 온 사람이 &quot;무엇이 어디 있는지&quot; 한눈에 파악하기 어렵다. 항목이 더 늘면 헤더가 넘치거나 줄바꿈된다.</li><li><strong>좌측 사이드바의 깊이·그룹 규칙이 섹션마다 제각각</strong>이다. 어떤 섹션은 단일 그룹, 어떤 섹션(Hermes)은 경로마다 &quot;프로젝트 개요&quot; 그룹이 중복 반복되고, Cowork 는 guide/test/tips/resources 4개 하위 네임스페이스가 상단의 단일 &quot;Cowork 가이드&quot; 진입점 뒤에 숨어 있어 발견성이 낮다.</li><li>그 결과 <strong>비슷한 콘텐츠가 흩어져</strong> 있고, 사용자는 원하는 문서까지 도달하는 데 불필요한 클릭과 추측을 반복한다.</li></ul><p>목적은 <strong>비슷한 성격의 콘텐츠를 상단에서 소수의 그룹(드롭다운)으로 묶고</strong>, <strong>좌측 사이드바의 계층 깊이와 그룹 규칙을 일관되게 정리</strong>하여, 방문자가 적은 클릭으로 원하는 콘텐츠에 도달할 수 있는 <strong>최적화된 메뉴 구조</strong>를 확정하는 것이다.</p><h2 id="clarifications" tabindex="-1">Clarifications <a class="header-anchor" href="#clarifications" aria-label="Permalink to &quot;Clarifications&quot;">​</a></h2><h3 id="session-2026-06-03" tabindex="-1">Session 2026-06-03 <a class="header-anchor" href="#session-2026-06-03" aria-label="Permalink to &quot;Session 2026-06-03&quot;">​</a></h3><ul><li>Q: 상단 메뉴를 몇 개의 그룹으로, 어떤 분류로 묶을까? → A: 3그룹 기본안 — <strong>개발 기록</strong>(개요·저널·명세) / <strong>학습 가이드</strong> / <strong>리포트·아카이브</strong>(Hermes· Blog Archive) + 홈 + GitHub.</li><li>Q: Cowork 하위 4영역(가이드/실습/팁/리소스)을 상단에서 어떻게 노출? → A: <strong>학습 가이드</strong> 드롭다운에 4영역을 <strong>직접 노출</strong>한다(스킬 강연 + Cowork 가이드·실습·팁·리소스).</li><li>Q: 좌측 사이드바 계층 깊이 상한은? → A: <strong>기본 2단(그룹 → 항목)</strong>, Hermes 벤치마크처럼 항목이 많은 섹션만 <strong>예외적으로 3단</strong> 허용.</li><li>Q: 사이드바 그룹 접힘(collapsed) 기본 규칙은? → A: <strong>항목 8개 초과 그룹만 기본 접힘</strong>, 그 이하는 펼침.</li></ul><h2 id="what-범위" tabindex="-1">What (범위) <a class="header-anchor" href="#what-범위" aria-label="Permalink to &quot;What (범위)&quot;">​</a></h2><h3 id="포함" tabindex="-1">포함 <a class="header-anchor" href="#포함" aria-label="Permalink to &quot;포함&quot;">​</a></h3><ul><li>상단 내비게이션을 <strong>주제별 그룹(드롭다운) 중심</strong>으로 재편 — 평평한 9개를 소수(약 3~4개)의 논리 그룹 + 홈 + 외부(GitHub) 링크로 묶는다.</li><li>좌측 사이드바의 <strong>계층 깊이 상한과 그룹/접힘 규칙을 표준화</strong> — 섹션 간 일관된 레벨 구조를 정의하고, 중복·고아 그룹을 정리한다.</li><li>각 상단 그룹과 좌측 사이드바 간의 <strong>매핑 규칙</strong>(어떤 그룹을 누르면 어떤 사이드바가 뜨는가) 정의.</li><li>기존 모든 콘텐츠 경로(URL)의 <strong>접근성 보존</strong> — 메뉴 위치가 바뀌어도 글 자체의 링크는 깨지지 않아야 한다.</li></ul><h3 id="제외-non-goals" tabindex="-1">제외 (Non-goals) <a class="header-anchor" href="#제외-non-goals" aria-label="Permalink to &quot;제외 (Non-goals)&quot;">​</a></h3><ul><li>콘텐츠 본문의 작성·수정·삭제(메뉴/구조만 다룬다).</li><li>기존 문서 URL(경로) 자체의 대규모 변경 — 필요한 경우 리다이렉트는 별도 후속 작업으로 다룬다.</li><li>새 디자인 테마·색상·폰트 등 시각 디자인 변경.</li><li>검색 엔진·전문(full-text) 검색 기능 변경.</li></ul><h2 id="user-scenarios" tabindex="-1">User Scenarios <a class="header-anchor" href="#user-scenarios" aria-label="Permalink to &quot;User Scenarios&quot;">​</a></h2><ol><li><strong>처음 방문자</strong>: 사이트에 처음 들어온 사람으로서, 상단 메뉴만 훑어도 &quot;개발 기록 / 학습 가이드 / 리포트&quot; 처럼 큰 갈래가 구분되어 보여, 관심 영역을 한 번에 고를 수 있다.</li><li><strong>반복 방문자</strong>: Cowork 가이드를 자주 보는 사람으로서, 상단 그룹을 열면 guide·test·tips·resources 하위 영역이 바로 보여, 매번 랜딩 페이지를 거치지 않고 원하는 하위 섹션으로 직행한다.</li><li><strong>깊은 문서 탐색자</strong>: Hermes 벤치마크의 특정 시나리오를 찾는 사람으로서, 좌측 사이드바의 일관된 2~3단 구조 덕분에 현재 위치와 상·하위 관계를 명확히 파악하고 헤맴 없이 이동한다.</li><li><strong>콘텐츠 추가자(저자)</strong>: 새 섹션을 추가하는 저자로서, 표준화된 레벨 규칙을 따르면 새 콘텐츠가 어느 상단 그룹·좌측 레벨에 들어갈지 규칙으로 결정되어, 구조가 일관되게 유지된다.</li></ol><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><h3 id="상단-내비게이션-top-nav" tabindex="-1">상단 내비게이션 (Top Nav) <a class="header-anchor" href="#상단-내비게이션-top-nav" aria-label="Permalink to &quot;상단 내비게이션 (Top Nav)&quot;">​</a></h3><ul><li><strong>FR-1</strong>: 상단 메뉴는 성격이 유사한 섹션을 묶은 <strong>소수의 그룹(드롭다운)</strong> 으로 구성한다. 평평하게 나열된 내부 진입점은 <strong>최대 5개 이하</strong>(홈 + 그룹들)로 줄인다.</li><li><strong>FR-2</strong>: 상단 그룹은 <strong>3개 + 홈 + GitHub</strong> 로 확정한다 — <strong>개발 기록</strong> (개요·저널·명세) / <strong>학습 가이드</strong> / <strong>리포트·아카이브</strong>(Hermes 보고서· Blog Archive). 각 그룹의 항목은 서로 <strong>주제적으로 응집</strong>되어야 한다.</li><li><strong>FR-3</strong>: 단일 항목뿐인 그룹은 드롭다운 대신 <strong>직접 링크</strong>로 둘 수 있다 (불필요한 한 단계 클릭 방지).</li><li><strong>FR-4</strong>: 외부 링크(GitHub)는 그룹과 분리해 식별 가능하게 표시한다.</li><li><strong>FR-5</strong>: 현재 보고 있는 섹션이 속한 상단 그룹은 <strong>활성 상태로 강조</strong>되어, 방문자가 자신의 현재 위치를 알 수 있다.</li></ul><h3 id="좌측-사이드바-sidebar" tabindex="-1">좌측 사이드바 (Sidebar) <a class="header-anchor" href="#좌측-사이드바-sidebar" aria-label="Permalink to &quot;좌측 사이드바 (Sidebar)&quot;">​</a></h3><ul><li><strong>FR-6</strong>: 좌측 사이드바 계층 깊이는 <strong>기본 2단(그룹 헤더 → 항목)</strong> 으로 하고, Hermes 벤치마크처럼 항목이 많은 섹션에 한해 <strong>예외적으로 3단</strong>(그룹 → 하위 그룹 → 항목)까지 허용한다. 모든 섹션이 이 상한을 따른다.</li><li><strong>FR-7</strong>: 사이드바 그룹의 접힘(collapsed) 기본값은 <strong>항목 8개 초과 그룹만 기본 접힘</strong>, 그 이하는 펼침으로 통일한다.</li><li><strong>FR-8</strong>: 경로마다 동일 그룹이 <strong>중복 반복되지 않도록</strong> 정리한다(현 Hermes 의 &quot;프로젝트 개요&quot; 반복 등).</li><li><strong>FR-9</strong>: 상단 그룹과 좌측 사이드바의 <strong>매핑이 결정적</strong>이어야 한다 — 특정 콘텐츠 경로를 열면 항상 같은 사이드바가 나타난다(고아/누락 사이드바 없음).</li><li><strong>FR-10</strong>: Cowork 의 하위 4영역(가이드/실습/팁/리소스)은 <strong>학습 가이드 드롭다운에 직접 노출</strong>한다(스킬 강연 + Cowork 가이드·실습·팁·리소스). 진입점 뒤에 숨기지 않는다.</li></ul><h3 id="보존-·-품질" tabindex="-1">보존 · 품질 <a class="header-anchor" href="#보존-·-품질" aria-label="Permalink to &quot;보존 · 품질&quot;">​</a></h3><ul><li><strong>FR-11</strong>: 재편 이후에도 <strong>기존 콘텐츠 문서로 가는 링크(URL)는 모두 살아 있어야</strong> 한다(메뉴에서 가리키던 모든 페이지가 여전히 도달 가능).</li><li><strong>FR-12</strong>: 변경된 구조는 <strong>VitePress 빌드(strict)</strong> 를 통과해야 한다 — 깨진 내부 링크가 없어야 한다.</li><li><strong>FR-13</strong>: 메뉴 구조는 데이터/설정으로 표현되어, 새 섹션 추가 시 규칙에 따라 <strong>확장 가능</strong>해야 한다.</li></ul><h2 id="success-criteria" tabindex="-1">Success Criteria <a class="header-anchor" href="#success-criteria" aria-label="Permalink to &quot;Success Criteria&quot;">​</a></h2><ul><li><strong>SC-1</strong>: 상단 내비게이션의 내부 최상위 진입점 수가 현재 8개에서 <strong>5개 이하</strong>로 줄어든다.</li><li><strong>SC-2</strong>: 임의의 콘텐츠 페이지에 도달하기까지 필요한 클릭 수가 <strong>상단 메뉴에서 최대 2클릭</strong>(그룹 열기 → 항목 선택) 이내다.</li><li><strong>SC-3</strong>: 모든 섹션의 좌측 사이드바 최대 깊이가 <strong>정의된 상한(2~3단) 이내</strong>로 일관된다.</li><li><strong>SC-4</strong>: 어떤 콘텐츠 경로를 열어도 <strong>올바른 사이드바가 100% 표시</strong>된다 (사이드바 누락·중복 0건).</li><li><strong>SC-5</strong>: 재편 전 도달 가능했던 <strong>모든 문서 URL 이 재편 후에도 100% 도달 가능</strong>하다(링크 회귀 0건).</li><li><strong>SC-6</strong>: 5명 내외의 첫 방문자 테스트에서, <strong>3개 대표 콘텐츠를 평균 2클릭 이내</strong>로 찾을 수 있다(탐색 성공률 향상).</li></ul><h2 id="key-entities" tabindex="-1">Key Entities <a class="header-anchor" href="#key-entities" aria-label="Permalink to &quot;Key Entities&quot;">​</a></h2><ul><li><strong>상단 메뉴 그룹(Nav Group)</strong>: 라벨 + 소속 항목 목록. 유사 콘텐츠의 묶음 단위.</li><li><strong>메뉴 항목(Nav Item)</strong>: 라벨 + 대상 경로(내부/외부) + 소속 그룹.</li><li><strong>사이드바 정의(Sidebar)</strong>: 경로 접두사(prefix) → 그룹/항목 트리. 계층 깊이·접힘 상태를 가진다.</li><li><strong>콘텐츠 섹션(Content Section)</strong>: 하나의 주제 영역(개요/저널/명세/스킬 강연/Cowork/Hermes/Blog Archive)과 그 하위 네임스페이스.</li></ul><h2 id="assumptions" tabindex="-1">Assumptions <a class="header-anchor" href="#assumptions" aria-label="Permalink to &quot;Assumptions&quot;">​</a></h2><ul><li><strong>확정 그룹안</strong>(Clarifications 2026-06-03): <ul><li><strong>홈</strong> — 단일 링크</li><li><strong>개발 기록</strong> ▾ — 개요 · 개발 저널 · 명세(Specs)</li><li><strong>학습 가이드</strong> ▾ — 스킬 강연 · Cowork 가이드 · Cowork 실습 · Cowork 팁 · Cowork 리소스 (Cowork 4영역 직접 노출)</li><li><strong>리포트 · 아카이브</strong> ▾ — Hermes 보고서 · Blog Archive</li><li><strong>GitHub</strong> — 외부 링크</li></ul></li><li>좌측 사이드바 <strong>깊이는 기본 2단(그룹 → 항목)</strong>, Hermes 벤치마크 등 항목이 많은 섹션에 한해 <strong>예외적으로 3단</strong>을 허용한다.</li><li>사이드바 <strong>접힘 기본값</strong>: 항목 8개 초과 그룹은 기본 접힘, 그 이하는 펼침.</li><li>기존 콘텐츠 파일 경로(URL)는 <strong>변경하지 않는다</strong>(메뉴 배치만 바꾼다).</li><li>변경은 VitePress 설정/사이드바 정의 파일 범위에서 이루어지며, 콘텐츠 Markdown 본문은 건드리지 않는다.</li><li>라벨은 기존 사이트 톤(한국어 우선)을 따른다.</li></ul><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><ul><li>초기 Open Questions(상단 그룹 개수·라벨, Blog Archive 배치, 3단 허용 범위)는 <strong>2026-06-03 Clarifications 에서 모두 해소</strong>되었다. 현재 미해결 결정 없음.</li></ul>',30)])])}const m=t(i,[["render",e]]);export{d as __pageData,m as default};
